UPDATE /*CustRequestMapper.updateCustRequestCallListScanId */
    NMCP_CUST_REQUEST_CALL_LIST
SET
    SCAN_ID = #{scanId}
WHERE 1 = 1
    AND CUST_REQ_SEQ = #{custReqSeq}

UPDATE /*CustRequestMapper.updateReqNmChgScanId */
    NMCP_CUST_REQUEST_NAME_CHG
SET
    SCAN_ID = #{scanId}
WHERE 1 = 1
    AND CUST_REQ_SEQ = #{custReqSeq}

